import outlines

@outlines.prompt
def build_prompt(question):
    '''I have a {{question}}'''

print(repr(build_prompt('cat')))

@outlines.prompt(filters={'reverse': lambda s: s[::-1]})
def reverse_prompt(text):
    '''{{ text | reverse }}'''

print(repr(reverse_prompt('hello')))

p = outlines.prompts.Prompt.from_str('{{ text | shout }}', filters={'shout': lambda s: s.upper() + '!'})
print(repr(p(text='hi')))
